"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[1193],{1193:e=>{e.exports=JSON.parse('{"25":{"words":[{"spanish":"D\xedmelo","english":"Tell it to me"},{"spanish":"No se lo digas","english":"Do not tell it to him or her"},{"spanish":"S\xedgame","english":"Follow me"},{"spanish":"T\xf3mela","english":"Take it"},{"spanish":"Ci\xe9rrala","english":"Close it"},{"spanish":"\xc1bralo","english":"Open it"},{"spanish":"Escr\xedbeme","english":"Write to me"},{"spanish":"No me llames tan tarde","english":"Do not call me so late"},{"spanish":"P\xf3nganse en fila","english":"Line up"},{"spanish":"Si\xe9ntese aqu\xed","english":"Sit here"},{"spanish":"Lev\xe1ntense despacio","english":"Stand up slowly"},{"spanish":"Mu\xe9stremelo","english":"Show it to me"},{"spanish":"Tr\xe1iganos la cuenta","english":"Bring us the check"},{"spanish":"No la cruce todav\xeda","english":"Do not cross it yet"},{"spanish":"Gire a la derecha","english":"Turn right"},{"spanish":"Doble a la izquierda","english":"Turn left"},{"spanish":"Siga derecho dos cuadras","english":"Go straight for two blocks"},{"spanish":"Cruce la calle","english":"Cross the street"},{"spanish":"La cuadra","english":"The block"},{"spanish":"La esquina","english":"The corner"},{"spanish":"El sem\xe1foro","english":"The traffic light"},{"spanish":"La avenida","english":"The avenue"},{"spanish":"La farmacia","english":"The pharmacy"},{"spanish":"La recepci\xf3n","english":"The front desk"},{"spanish":"Entr\xe9gueselo","english":"Hand it to him or her"},{"spanish":"No se lo mande hoy","english":"Do not send it to him or her today"},{"spanish":"P\xe1samela","english":"Pass it to me"},{"spanish":"Ponlos aqu\xed","english":"Put them here"},{"spanish":"No las abras","english":"Do not open them"},{"spanish":"Expl\xedqueselo con calma","english":"Explain it to him or her calmly"},{"spanish":"Denme un minuto","english":"Give me a minute"},{"spanish":"H\xe1ganlo ahora","english":"Do it now"},{"spanish":"Vaya hasta el puente","english":"Go as far as the bridge"},{"spanish":"Tome la segunda salida","english":"Take the second exit"},{"spanish":"Qu\xe9dese cerca de la puerta","english":"Stay near the door"},{"spanish":"No se vaya sin su recibo","english":"Do not leave without your receipt"},{"spanish":"El mapa","english":"The map"},{"spanish":"La direcci\xf3n","english":"The address"},{"spanish":"El paquete","english":"The package"},{"spanish":"El formulario","english":"The form"},{"spanish":"La oficina de correos","english":"The post office"},{"spanish":"La puerta de embarque","english":"The boarding gate"}],"conversations":[{"id":1,"topic":"Pedir indicaciones en el centro","dialog":[{"speaker":"Marina","spanish":"Disculpe, se\xf1or agente, \xbfc\xf3mo llego a la farmacia central?","english":"Excuse me, officer, how do I get to the main pharmacy?"},{"speaker":"Agente Ruiz","spanish":"Siga derecho dos cuadras, gire a la derecha en el sem\xe1foro y cruce la avenida con cuidado.","english":"Go straight for two blocks, turn right at the traffic light, and cross the avenue carefully."},{"speaker":"Marina","spanish":"\xbfLa farmacia queda cerca del banco o del mercado?","english":"Is the pharmacy near the bank or the market?"},{"speaker":"Agente Ruiz","spanish":"Queda junto al banco. Cuando vea la esquina con una panader\xeda verde, doble a la izquierda y la ver\xe1 enseguida.","english":"It is next to the bank. When you see the corner with a green bakery, turn left and you will see it right away."},{"speaker":"Marina","spanish":"Gracias. \xbfPuedo pasar por este parque?","english":"Thank you. Can I go through this park?"},{"speaker":"Agente Ruiz","spanish":"S\xed, atravi\xe9selo si quiere ahorrar tiempo, pero no cruce por la mitad de la calle.","english":"Yes, go through it if you want to save time, but do not cross in the middle of the street."}],"questions":[{"question":"\xbfQu\xe9 referencia usa el agente para ubicar la farmacia?","options":["Est\xe1 frente al hospital","Est\xe1 junto al banco","Est\xe1 detr\xe1s del mercado","Est\xe1 al lado de la estaci\xf3n"],"answer":"Est\xe1 junto al banco","answerIndex":1},{"question":"\xbfQu\xe9 puede hacer Marina si quiere ahorrar tiempo?","options":["Tomar un taxi en la esquina","Cruzar la avenida dos veces","Atravesar el parque","Esperar en la panader\xeda"],"answer":"Atravesar el parque","answerIndex":2},{"question":"\xbfQu\xe9 advertencia le da el agente a Marina?","options":["Que no cruce por la mitad de la calle","Que no entre en la farmacia todav\xeda","Que no hable con el banco","Que no use el sem\xe1foro"],"answer":"Que no cruce por la mitad de la calle","answerIndex":0}]},{"id":2,"topic":"Instrucciones en un restaurante","dialog":[{"speaker":"Elena","spanish":"Diego, ll\xe9vale esta sopa a la mesa siete y diles que el plato fuerte sale en cinco minutos.","english":"Diego, take this soup to table seven and tell them the main course will be ready in five minutes."},{"speaker":"Diego","spanish":"De acuerdo. \xbfTambi\xe9n les llevo el pan ahora?","english":"All right. Should I also take them the bread now?"},{"speaker":"Elena","spanish":"S\xed, tr\xe1eselo, pero no se lo pongas a la se\xf1ora al\xe9rgica; d\xe9jalo en el centro de la mesa.","english":"Yes, bring it to them, but do not place it in front of the woman with allergies; leave it in the middle of the table."},{"speaker":"Diego","spanish":"Entendido. \xbfLe digo al cajero que prepare la cuenta?","english":"Understood. Should I tell the cashier to prepare the bill?"},{"speaker":"Elena","spanish":"S\xed, d\xedmelo cuando regreses y luego tr\xe1enos las bebidas para la mesa ocho.","english":"Yes, tell me when you come back and then bring us the drinks for table eight."},{"speaker":"Diego","spanish":"Perfecto, chef. No se me olvida nada esta vez.","english":"Perfect, chef. I will not forget anything this time."}],"questions":[{"question":"\xbfQui\xe9n no debe recibir el pan directamente?","options":["La se\xf1ora al\xe9rgica","El cajero del restaurante","La mesa ocho","El cliente que pidi\xf3 sopa"],"answer":"La se\xf1ora al\xe9rgica","answerIndex":0},{"question":"\xbfQu\xe9 debe hacer Diego cuando regrese?","options":["Cerrar la cocina","Decirle algo a Elena sobre la cuenta","Llevar la sopa a la mesa ocho","Preguntar por la panader\xeda"],"answer":"Decirle algo a Elena sobre la cuenta","answerIndex":1},{"question":"\xbfPara qu\xe9 mesa piden las bebidas?","options":["Para la mesa tres","Para la mesa cinco","Para la mesa siete","Para la mesa ocho"],"answer":"Para la mesa ocho","answerIndex":3}]},{"id":3,"topic":"Retiro de un paquete en recepci\xf3n","dialog":[{"speaker":"Nora","spanish":"Se\xf1or P\xe9rez, firme aqu\xed y mu\xe9streme su identificaci\xf3n, por favor.","english":"Mr. P\xe9rez, sign here and show me your identification, please."},{"speaker":"Se\xf1or P\xe9rez","spanish":"Claro. \xbfRecojo el paquete en esta ventanilla?","english":"Of course. Do I pick up the package at this window?"},{"speaker":"Nora","spanish":"No, ll\xe9veselo primero al guardia del fondo para que lo registre y luego tr\xe1igamelo otra vez.","english":"No, first take it to the guard in the back so he can register it, and then bring it back to me."},{"speaker":"Se\xf1or P\xe9rez","spanish":"Entiendo. \xbfAbro la caja antes de salir?","english":"I understand. Should I open the box before leaving?"},{"speaker":"Nora","spanish":"No la abra aqu\xed. Gu\xe1rdela cerrada y no se vaya sin su recibo.","english":"Do not open it here. Keep it closed and do not leave without your receipt."},{"speaker":"Se\xf1or P\xe9rez","spanish":"Perfecto. Se lo entrego al guardia y luego vuelvo con usted.","english":"Perfect. I will hand it to the guard and then come back to you."}],"questions":[{"question":"\xbfQui\xe9n debe registrar primero el paquete?","options":["El guardia del fondo","La cajera principal","El mismo se\xf1or P\xe9rez","El mensajero externo"],"answer":"El guardia del fondo","answerIndex":0},{"question":"\xbfQu\xe9 no debe abrir el se\xf1or P\xe9rez dentro de la recepci\xf3n?","options":["El formulario","La puerta lateral","La caja del paquete","La identificaci\xf3n"],"answer":"La caja del paquete","answerIndex":2},{"question":"\xbfQu\xe9 debe llevarse antes de irse?","options":["Su recibo","La llave del edificio","Una copia del mapa","La credencial de Nora"],"answer":"Su recibo","answerIndex":0}]},{"id":4,"topic":"Preparativos para un viaje por carretera","dialog":[{"speaker":"Andr\xe9s","spanish":"Sofi, p\xe1same el cargador y ponlo en la mochila peque\xf1a.","english":"Sofi, pass me the charger and put it in the small backpack."},{"speaker":"Sof\xeda","spanish":"Aqu\xed est\xe1. \xbfTambi\xe9n te guardo los bocadillos?","english":"Here it is. Should I also pack the snacks for you?"},{"speaker":"Andr\xe9s","spanish":"S\xed, gu\xe1rdalos, pero no los metas en la nevera azul; d\xe9jala para las bebidas.","english":"Yes, pack them, but do not put them in the blue cooler; leave that one for the drinks."},{"speaker":"Sof\xeda","spanish":"Vale. \xbfLe escribo a Carla para decirle que salimos tarde?","english":"Okay. Should I write to Carla to tell her we are leaving late?"},{"speaker":"Andr\xe9s","spanish":"S\xed, escr\xedbeselo ahora y luego dime si puede esperarnos en la gasolinera.","english":"Yes, write it to her now and then tell me whether she can wait for us at the gas station."},{"speaker":"Sof\xeda","spanish":"Hecho. Tambi\xe9n ll\xe9vate el mapa por si el GPS falla.","english":"Done. Also take the map in case the GPS fails."}],"questions":[{"question":"\xbfD\xf3nde quiere Andr\xe9s que pongan el cargador?","options":["En la guantera del coche","En la mochila peque\xf1a","En la nevera azul","En el asiento trasero"],"answer":"En la mochila peque\xf1a","answerIndex":1},{"question":"\xbfPara qu\xe9 debe quedar libre la nevera azul?","options":["Para las bebidas","Para los bocadillos","Para el cargador","Para los mapas"],"answer":"Para las bebidas","answerIndex":0},{"question":"\xbfPor qu\xe9 sugiere Sof\xeda llevarse el mapa?","options":["Porque van a visitar una biblioteca","Porque Carla no sabe usar el tel\xe9fono","Porque el GPS podr\xeda fallar","Porque la gasolinera est\xe1 cerrada"],"answer":"Porque el GPS podr\xeda fallar","answerIndex":2}]}],"stories":[{"id":1,"title":"La visita guiada","sentences":[{"spanish":"Cuando lleg\xf3 el grupo al centro hist\xf3rico, la gu\xeda les pidi\xf3 que se acercaran y que no se separaran.","english":"When the group arrived in the historic center, the guide asked them to come closer and not separate."},{"spanish":"Luego les dijo: Sigan derecho hasta la plaza, miren la torre y tomen fotos sin bloquear la entrada.","english":"Then she told them: Go straight to the square, look at the tower, and take pictures without blocking the entrance."},{"spanish":"A una pareja mayor le recomend\xf3 que se sentara un momento antes de subir las escaleras.","english":"She recommended that an older couple sit down for a moment before climbing the stairs."},{"spanish":"M\xe1s tarde, un turista le pregunt\xf3 por el museo y ella le respondi\xf3: Cruce la calle y b\xfasquelo junto al teatro.","english":"Later, a tourist asked her about the museum and she replied: Cross the street and look for it next to the theater."},{"spanish":"Antes de entrar al edificio, la gu\xeda insisti\xf3 en que guardaran los paraguas y apagaran el sonido del tel\xe9fono.","english":"Before entering the building, the guide insisted that they put away their umbrellas and silence their phones."},{"spanish":"Gracias a esas instrucciones claras, nadie se perdi\xf3 y todos disfrutaron mejor el recorrido.","english":"Thanks to those clear instructions, no one got lost and everyone enjoyed the tour more."}]},{"id":2,"title":"El paquete urgente","sentences":[{"spanish":"Nora recibi\xf3 un paquete urgente en la recepci\xf3n y llam\xf3 al se\xf1or P\xe9rez para que pasara por \xe9l.","english":"Nora received an urgent package at the front desk and called Mr. P\xe9rez so he could pick it up."},{"spanish":"Cuando \xe9l lleg\xf3, ella le dijo que firmara primero y que le mostrara una identificaci\xf3n oficial.","english":"When he arrived, she told him to sign first and show her an official ID."},{"spanish":"Despu\xe9s, le explic\xf3 que se lo llevara al guardia y que no abriera la caja dentro del edificio.","english":"Afterward, she explained that he should take it to the guard and not open the box inside the building."},{"spanish":"El guardia revis\xf3 el c\xf3digo y le devolvi\xf3 el paquete con rapidez.","english":"The guard checked the code and returned the package quickly."},{"spanish":"Antes de salir, Nora le record\xf3: No se vaya sin su recibo y gu\xe1rdelo por si hay un reclamo.","english":"Before leaving, Nora reminded him: Do not leave without your receipt and keep it in case there is a claim."},{"spanish":"El se\xf1or P\xe9rez sigui\xf3 cada paso y evit\xf3 un problema que ya hab\xeda retrasado a otros clientes.","english":"Mr. P\xe9rez followed each step and avoided a problem that had already delayed other customers."}]},{"id":3,"title":"La mudanza del s\xe1bado","sentences":[{"spanish":"El s\xe1bado por la ma\xf1ana, varios amigos llegaron para ayudar a Julia con su mudanza.","english":"On Saturday morning, several friends arrived to help Julia with her move."},{"spanish":"Ella les pidi\xf3: Suban primero las cajas peque\xf1as y dejen la mesa para el final.","english":"She asked them: Carry up the small boxes first and leave the table for the end."},{"spanish":"A Marcos le dijo que cerrara bien la puerta del cami\xf3n y que no dejara nada en la acera.","english":"She told Marcos to close the truck door tightly and not leave anything on the sidewalk."},{"spanish":"Luego le grit\xf3 a Paula desde la cocina: P\xe1same los vasos, pero no los pongas junto a los libros.","english":"Then she called to Paula from the kitchen: Pass me the glasses, but do not put them next to the books."},{"spanish":"Cuando ya faltaba poco, todos se sentaron a descansar y Julia les trajo agua.","english":"When only a little remained, everyone sat down to rest and Julia brought them water."},{"spanish":"La jornada fue larga, pero las instrucciones precisas hicieron que todo terminara sin da\xf1os.","english":"The day was long, but the precise instructions made everything end without damage."}]}],"speaking":{"title":"Pr\xe1ctica oral de mandatos y pronombres","description":"Da instrucciones, peticiones y direcciones usando mandatos formales e informales con pronombres de objeto.","questions_and_answers":[{"question":{"spanish":"Di en espa\xf1ol: Tell it to me right now.","english":"Say in Spanish: Tell it to me right now."},"answer":{"spanish":"D\xedmelo ahora mismo.","english":"Tell it to me right now."}},{"question":{"spanish":"Di en espa\xf1ol: Do not explain it to him yet.","english":"Say in Spanish: Do not explain it to him yet."},"answer":{"spanish":"No se lo expliques todav\xeda.","english":"Do not explain it to him yet."}},{"question":{"spanish":"Di en espa\xf1ol: Follow me to the front desk.","english":"Say in Spanish: Follow me to the front desk."},"answer":{"spanish":"S\xedgame hasta la recepci\xf3n.","english":"Follow me to the front desk."}},{"question":{"spanish":"Di en espa\xf1ol: Take it with water after eating.","english":"Say in Spanish: Take it with water after eating."},"answer":{"spanish":"T\xf3mela con agua despu\xe9s de comer.","english":"Take it with water after eating."}},{"question":{"spanish":"Di en espa\xf1ol: Close it before leaving.","english":"Say in Spanish: Close it before leaving."},"answer":{"spanish":"Ci\xe9rrala antes de salir.","english":"Close it before leaving."}},{"question":{"spanish":"Di en espa\xf1ol: Turn left at the next corner.","english":"Say in Spanish: Turn left at the next corner."},"answer":{"spanish":"Gire a la izquierda en la pr\xf3xima esquina.","english":"Turn left at the next corner."}},{"question":{"spanish":"Di en espa\xf1ol: Go straight for three blocks.","english":"Say in Spanish: Go straight for three blocks."},"answer":{"spanish":"Siga derecho tres cuadras.","english":"Go straight for three blocks."}},{"question":{"spanish":"Di en espa\xf1ol: Cross the bridge and then turn right.","english":"Say in Spanish: Cross the bridge and then turn right."},"answer":{"spanish":"Cruce el puente y luego doble a la derecha.","english":"Cross the bridge and then turn right."}},{"question":{"spanish":"Di en espa\xf1ol: Pass them to me when you finish.","english":"Say in Spanish: Pass them to me when you finish."},"answer":{"spanish":"P\xe1samelas cuando termines.","english":"Pass them to me when you finish."}},{"question":{"spanish":"Di en espa\xf1ol: Do not send it to me by message.","english":"Say in Spanish: Do not send it to me by message."},"answer":{"spanish":"No me lo mandes por mensaje.","english":"Do not send it to me by message."}},{"question":{"spanish":"Di en espa\xf1ol: Hand it to the principal, please.","english":"Say in Spanish: Hand it to the principal, please."},"answer":{"spanish":"Entr\xe9gueselo a la directora, por favor.","english":"Hand it to the principal, please."}},{"question":{"spanish":"Di en espa\xf1ol: Do it carefully and quietly.","english":"Say in Spanish: Do it carefully and quietly."},"answer":{"spanish":"H\xe1ganlo con cuidado y en silencio.","english":"Do it carefully and quietly."}},{"question":{"spanish":"Di en espa\xf1ol: Sit near the door.","english":"Say in Spanish: Sit near the door."},"answer":{"spanish":"Si\xe9ntense cerca de la puerta.","english":"Sit near the door."}},{"question":{"spanish":"Di en espa\xf1ol: Do not leave without your tickets.","english":"Say in Spanish: Do not leave without your tickets."},"answer":{"spanish":"No se vayan sin sus boletos.","english":"Do not leave without your tickets."}},{"question":{"spanish":"Di en espa\xf1ol: Show it to me on the screen.","english":"Say in Spanish: Show it to me on the screen."},"answer":{"spanish":"Mu\xe9stremelo en la pantalla.","english":"Show it to me on the screen."}},{"question":{"spanish":"Di en espa\xf1ol: Bring us two coffees and the check.","english":"Say in Spanish: Bring us two coffees and the check."},"answer":{"spanish":"Tr\xe1iganos dos caf\xe9s y la cuenta.","english":"Bring us two coffees and the check."}},{"question":{"spanish":"Di en espa\xf1ol: Do not open them until tomorrow.","english":"Say in Spanish: Do not open them until tomorrow."},"answer":{"spanish":"No las abras hasta ma\xf1ana.","english":"Do not open them until tomorrow."}},{"question":{"spanish":"Di en espa\xf1ol: Take the second exit toward downtown.","english":"Say in Spanish: Take the second exit toward downtown."},"answer":{"spanish":"Tome la segunda salida hacia el centro.","english":"Take the second exit toward downtown."}},{"question":{"spanish":"Di en espa\xf1ol: Write to me when you get to the station.","english":"Say in Spanish: Write to me when you get to the station."},"answer":{"spanish":"Escr\xedbeme cuando llegues a la estaci\xf3n.","english":"Write to me when you get to the station."}},{"question":{"spanish":"Di en espa\xf1ol: Put them on the kitchen table.","english":"Say in Spanish: Put them on the kitchen table."},"answer":{"spanish":"P\xf3ngalos sobre la mesa de la cocina.","english":"Put them on the kitchen table."}}]}}}')}}]);